   436	impl<'a> Format<'a> for ArrowChain<'a, '_> {
   437	    fn fmt(&self, f: &mut Formatter<'_, 'a>) {
   438	        let ArrowChain { tail, expand_signatures, .. } = *self;
   439	
   440	        let tail_body = tail.body();
   441	        let is_grouped_call_arg_layout = self.options.call_argument_layout.is_some();
   442	
   443	        // If this chain is the callee in a parent call expression, then we
   444	        // want it to break onto a new line to clearly show that the arrow
   445	        // chain is distinct and the _result_ is what's being called.
   446	        // Example:
   447	        //      (() => () => a)()
   448	        // becomes
   449	        //      (
   450	        //        () => () =>
   451	        //          a
   452	        //      )();
   453	        let is_callee = self.head.is_call_like_callee();
   454	
   455	        // With arrays, objects, sequence expressions, and block function bodies,
   456	        // the opening brace gives a convenient boundary to insert a line break,
   457	        // allowing that token to live immediately after the last arrow token
   458	        // and save a line from being printed with just the punctuation.
   459	        //
   460	        // (foo) => (bar) => [a, b]
   461	        //
   462	        // (foo) => (bar) => [
   463	        //   a,
   464	        //   b
   465	        // ]
   466	        //
   467	        // If the body is _not_ one of those kinds, then we'll want to insert a
   468	        // soft line break before the body so that it prints on a separate line
   469	        // in its entirety.
   470	        let body_on_separate_line = !tail.get_expression().is_none_or(|expression| {
   471	            matches!(
   472	                expression,
   473	                Expression::ObjectExpression(_)
   474	                    | Expression::ArrayExpression(_)
   475	                    | Expression::SequenceExpression(_)
   476	                    | Expression::JSXElement(_)
   477	                    | Expression::JSXFragment(_)
   478	            )
   479	        });
