   516	fn is_relatively_short_argument(argument: &Expression<'_>) -> bool {
   517	    match argument {
   518	        Expression::BinaryExpression(binary) => {
   519	            SimpleArgument::from(&binary.left).is_simple_with_depth(1)
   520	                && SimpleArgument::from(&binary.right).is_simple_with_depth(1)
   521	        }
   522	        Expression::LogicalExpression(logical) => {
   523	            SimpleArgument::from(&logical.left).is_simple_with_depth(1)
   524	                && SimpleArgument::from(&logical.right).is_simple_with_depth(1)
   525	        }
   526	        Expression::TSAsExpression(expr) => {
   527	            is_simple_ts_type(&expr.type_annotation)
   528	                && SimpleArgument::from(&expr.expression).is_simple_with_depth(1)
   529	        }
   530	        Expression::TSSatisfiesExpression(expr) => {
   531	            is_simple_ts_type(&expr.type_annotation)
   532	                && SimpleArgument::from(&expr.expression).is_simple_with_depth(1)
   533	        }
   534	        Expression::RegExpLiteral(_) => true,
   535	        Expression::CallExpression(call) => match call.arguments.len() {
   536	            0 => true,
   537	            1 => SimpleArgument::from(argument).is_simple(),
   538	            _ => false,
   539	        },
   540	        _ => SimpleArgument::from(argument).is_simple(),
   541	    }
   542	}
