fn is_type_cast_expression_body(expression: &Expression<'_>, f: &Formatter<'_, '_>) -> bool {
    let mut current = expression;

    loop {
        if has_type_cast_comment_before(current, f) || is_type_cast_node(current, f).is_some() {
            return true;
        }

        let Expression::ParenthesizedExpression(parenthesized) = current else {
            return false;
