fn has_type_cast_comment_before(expression: &Expression<'_>, f: &Formatter<'_, '_>) -> bool {
    let comments = f.comments();
    let source = f.source_text();
    let span_start = expression.span().start;

    comments
        .printed_comments()
        .iter()
        .chain(comments.unprinted_comments())
        .take_while(|comment| comment.span.end <= span_start)
        .last()
        .is_some_and(|comment| {
            comments.is_type_cast_comment(comment)
                && source.next_non_whitespace_byte_is(comment.span.end, b'(')
                && source.all_bytes_match(comment.span.end, span_start, |byte| {
                    byte.is_ascii_whitespace() || byte == b'('
                })
        })
}

